insert into public.categories(name,slug,description,icon,sort_order)values('Chocolates','chocolates','Cremosos, crujientes y deliciosos.','🍫',1),('Gomitas','gomitas','Suaves, ácidas y enchiladas.','🍬',2),('Paletas','paletas','Sabores para disfrutar sin prisa.','🍭',3),('Dulces mexicanos','dulces-mexicanos','Los clásicos de siempre.','🪅',4) on conflict(slug)do update set icon=excluded.icon;
with c as(select id,slug from categories)insert into products(category_id,name,slug,description,sku,price,offer_price,image_url,is_featured,stock,track_stock)values
((select id from c where slug='dulces-mexicanos'),'Mazapán De la Rosa','mazapan-de-la-rosa','El clásico de cacahuate.','MZP-01',12,10,'https://images.unsplash.com/photo-1582058091505-f87a2e55a40f?auto=format&fit=crop&w=800&q=80',true,40,true),
((select id from c where slug='gomitas'),'Gomitas enchiladas','gomitas-enchiladas','Gomitas frutales con chile.','GOM-01',45,39,'https://images.unsplash.com/photo-1581798459219-318e76aecc7b?auto=format&fit=crop&w=800&q=80',true,25,true),
((select id from c where slug='chocolates'),'Chocolate con almendras','chocolate-almendras','Chocolate suave con almendras.','CHO-01',55,null,'https://images.unsplash.com/photo-1575377427642-087cf684f29d?auto=format&fit=crop&w=800&q=80',true,null,false),
((select id from c where slug='paletas'),'Paleta arcoíris','paleta-arcoiris','Color y sabor para celebrar.','PAL-01',28,22,'https://images.unsplash.com/photo-1575224300306-1b8da36134ec?auto=format&fit=crop&w=800&q=80',false,30,true),
((select id from c where slug='dulces-mexicanos'),'Cocada artesanal','cocada-artesanal','Dulce tradicional de coco.','MEX-02',25,null,null,false,null,false),((select id from c where slug='dulces-mexicanos'),'Alegría de amaranto','alegria-amaranto','Amaranto con miel.','MEX-03',22,null,null,false,null,false),((select id from c where slug='gomitas'),'Ositos frutales','ositos-frutales','Ositos de muchos sabores.','GOM-02',38,null,null,false,18,true),((select id from c where slug='gomitas'),'Aros ácidos','aros-acidos','El toque ácido perfecto.','GOM-03',42,null,null,false,null,false),((select id from c where slug='chocolates'),'Trufas de cacao','trufas-cacao','Trufas intensas y suaves.','CHO-02',65,null,null,false,12,true),((select id from c where slug='chocolates'),'Chocolate blanco','chocolate-blanco','Dulce y cremoso.','CHO-03',48,null,null,false,null,false),((select id from c where slug='paletas'),'Paleta de mango','paleta-mango','Mango con un toque de chile.','PAL-02',20,null,null,false,50,true),((select id from c where slug='paletas'),'Paleta de caramelo','paleta-caramelo','Un clásico brillante.','PAL-03',18,null,null,false,null,false)on conflict(slug)do nothing;
